import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Subheader, FormDisplay, headerActions, headerStrings } from '../../../../includes';
import { insureUtilStrings, insureActions } from '../../../utils';
import { KnowledgeArea } from '../../../Home/KnowledeArea';
import { Button } from '@material-ui/core';
import { appActions, alertAction } from '../../../../../actions';
import { insureServiceActions } from '../../actions';
import { getFormDisplayData } from '../../../../includes/Forms/FormDisplay/functions';


const style = theme => ({
    root: {
    },
    container : {
        display : "flex",
        flexDirection : "column",
        marginTop : 100,
        marginBottom : 50,
        [theme.breakpoints.up("sm")] : {
            margin : 100,
        },
        [theme.breakpoints.up("md")] : {
            margin : "100px 200px",
        },
    }
})
class _CoopReg extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {

            }
        }
        const {dispatch } = props;
        headerActions({
            [headerStrings.headerTitle] : "Cooperative Registration"
        })(dispatch)
    }
    componentDidMount() {
        const {
            dispatch,
            [insureUtilStrings.forms] : forms
        } = this.props;
        if(!forms) insureActions.getForms()(dispatch);
    }
    
    handleCreateClient = e => {
        const {dispatch} = this.props;
        // let newData = {};
        const {inputFieldContexes} = this.formDisplayContext;
        const newData = getFormDisplayData(this.formDisplayContext)((message, type)=>{
            appActions.showSnackbar(alertAction[type](message))(dispatch);
            return false;
        });
        if(newData) insureServiceActions.newCoopReg(newData, done=>{
            if(done) for (const name in inputFieldContexes) {
                if (inputFieldContexes.hasOwnProperty(name)) {
                    const context = inputFieldContexes[name];
                    context.setState({data : {}});
                }
            }
        })(dispatch);
    }
    getFormDisplayContext = context => this.formDisplayContext = context;
    render() {
        const {
            classes, 
            [insureUtilStrings.subheadImage] : subheadImage,
            [insureUtilStrings.forms] : forms
        } = this.props;
        let coopRegItem;
        if(forms){
            const formFilter = forms.getFirstObjectByPropValue("name", "coopRegConfig") || {};
            coopRegItem = formFilter.item;
        }
        return (
            <div className={classes.root}>
                <Subheader
                    image_url={subheadImage}
                    title="Cooperative Registration"/>

                <div className={classes.container}>
                    <FormDisplay
                        formName="coopReg"
                        header="Registration Form"
                        formConfig={coopRegItem && coopRegItem.value}
                        getContext={this.getFormDisplayContext.bind(this)}
                        footer={({context})=><div style={{marginTop : 50}}>
                            <Button onClick={this.handleCreateClient.bind(this)} variant="contained" color="primary">Create</Button>
                        </div>}/>
                </div>
                <KnowledgeArea/>
            </div>
        );
    }
}


_CoopReg.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUtilReducer}) => ({
    [insureUtilStrings.subheadImage] : insureUtilReducer[insureUtilStrings.subheadImage],
    [insureUtilStrings.forms] : insureUtilReducer[insureUtilStrings.forms],
})


export const CoopReg = connect(mapStateToProps)(withStyles(style)(_CoopReg));
export {CoopReg as default}